module VCO (  
    input clk,  
    input reset,  
    input [3:0] V_ctl,  
    output reg [3:0] frequency_out  
);  

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin  
        if (reset)  
            frequency_out <= 4'b0000;  
        else begin  
            // The output frequency is directly proportional to the control voltage  
            frequency_out <= V_ctl;  
        end  
    end  
endmodule
